import{_ as a,o as d,c as e,a3 as r}from"./chunks/framework.Daqi0Atb.js";const n="/assets/02-01.D_gLs_Cw.jpg",o="/assets/02-02.D7RdV9AW.jpg",s="/assets/02-03.9ukDt7us.jpg",q=JSON.parse('{"title":"02｜双轴框架（上）：理解认知功能与执行拓扑","description":"","frontmatter":{},"headers":[],"relativePath":"courses/agent-design/02-双轴框架（上）：理解认知功能与执行拓扑.md","filePath":"courses/agent-design/02-双轴框架（上）：理解认知功能与执行拓扑.md"}'),l={name:"courses/agent-design/02-双轴框架（上）：理解认知功能与执行拓扑.md"};function i(h,t,p,g,c,u){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="_02-双轴框架-上-理解认知功能与执行拓扑" tabindex="-1">02｜双轴框架（上）：理解认知功能与执行拓扑 <a class="header-anchor" href="#_02-双轴框架-上-理解认知功能与执行拓扑" aria-label="Permalink to &quot;02｜双轴框架（上）：理解认知功能与执行拓扑&quot;">​</a></h1><p><strong>作者</strong>：黄佳</p><hr><h2 id="一句话脉络" tabindex="-1">一句话脉络 <a class="header-anchor" href="#一句话脉络" aria-label="Permalink to &quot;一句话脉络&quot;">​</a></h2><ul><li>双轴框架 = <strong>What（认知功能）</strong> × <strong>How（执行拓扑）</strong></li><li>纵轴回答&quot;Agent 在消耗哪种资源&quot;</li><li>横轴回答&quot;错误如何在系统里传播&quot;</li></ul><hr><h2 id="为什么需要双轴坐标系" tabindex="-1">为什么需要双轴坐标系 <a class="header-anchor" href="#为什么需要双轴坐标系" aria-label="Permalink to &quot;为什么需要双轴坐标系&quot;">​</a></h2><p>业界 5 类主流分类说法（Weng 数模块、Anthropic 数 Workflow、Andrew Ng 数模式、Chip Huyen 数工程角色）都对，但都不是同一层的东西——像从不同方向给同一个立方体画三视图，每个视图都是真的，但没有一张能还原整体结构。</p><p>三大盲区：</p><ol><li><strong>感知盲区</strong> — 默认 LLM 拿到的 input 是对的，但生产系统最先死的往往就是 input。感知是注意力预算的第一道闸，不是前处理小步骤。</li><li><strong>反思盲区</strong> — Reflection 常被折进 Reasoning，好像只是推理的技巧。但反思是把&quot;一次性回答&quot;推进到&quot;可迭代改进&quot;的关键机制，应该独立成脉。</li><li><strong>治理盲区</strong> — Demo 可以没有治理，工程不能没有。治理必须和行动能力一起设计，不是上线前临时补丁。</li></ol><hr><h2 id="纵轴-七脉-认知功能" tabindex="-1">纵轴：七脉（认知功能） <a class="header-anchor" href="#纵轴-七脉-认知功能" aria-label="Permalink to &quot;纵轴：七脉（认知功能）&quot;">​</a></h2><p><img src="'+n+`" alt="七脉（认知功能）示意"></p><table tabindex="0"><thead><tr><th>认知层</th><th>资源预算</th><th>核心问题</th></tr></thead><tbody><tr><td>感知</td><td>注意力预算</td><td>什么信息值得进入模型，什么留在外面</td></tr><tr><td>记忆</td><td>连续性预算</td><td>Agent 跨时间保留什么</td></tr><tr><td>推理</td><td>不确定性预算</td><td>怎么从前提走到结论</td></tr><tr><td>行动</td><td>可逆性预算</td><td>Agent 能对世界做什么，做了之后能否撤回</td></tr><tr><td>反思</td><td>校正预算</td><td>刚才做得对不对，错在哪里，下一步怎么改</td></tr><tr><td>协作</td><td>分工预算</td><td>任务怎么拆给多个 Agent</td></tr><tr><td>治理</td><td>信任预算</td><td>Agent 的能力如何被限制、记录、审计、追责</td></tr></tbody></table><h3 id="七脉三层" tabindex="-1">七脉三层 <a class="header-anchor" href="#七脉三层" aria-label="Permalink to &quot;七脉三层&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>内圈（核心认知）：感知 → 记忆 → 推理 → 行动</span></span>
<span class="line"><span>    让 Agent 能用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中圈（元认知）：反思</span></span>
<span class="line"><span>    让 Agent 可靠</span></span>
<span class="line"><span></span></span>
<span class="line"><span>外圈（系统智能）：协作 + 治理</span></span>
<span class="line"><span>    让 Agent 能上线</span></span></code></pre></div><h3 id="七脉失配后的表现" tabindex="-1">七脉失配后的表现 <a class="header-anchor" href="#七脉失配后的表现" aria-label="Permalink to &quot;七脉失配后的表现&quot;">​</a></h3><table tabindex="0"><thead><tr><th>缺哪脉</th><th>失控表现</th></tr></thead><tbody><tr><td>缺感知</td><td>token 失控</td></tr><tr><td>缺记忆</td><td>连续性失控</td></tr><tr><td>缺推理</td><td>判断失控</td></tr><tr><td>缺行动约束</td><td>世界状态失控</td></tr><tr><td>缺反思</td><td>错误失控</td></tr><tr><td>缺协作</td><td>规模失控</td></tr><tr><td>缺治理</td><td>信任失控</td></tr></tbody></table><hr><h2 id="横轴-六式-执行拓扑" tabindex="-1">横轴：六式（执行拓扑） <a class="header-anchor" href="#横轴-六式-执行拓扑" aria-label="Permalink to &quot;横轴：六式（执行拓扑）&quot;">​</a></h2><p><img src="`+o+'" alt="六式（执行拓扑）示意"></p><table tabindex="0"><thead><tr><th>拓扑</th><th>动词</th><th>错误传播方式</th></tr></thead><tbody><tr><td>Chain（链式）</td><td>传</td><td>错误级联——一步走偏，顺流而下，下游不会纠错反而包装错误</td></tr><tr><td>Route（路由）</td><td>选</td><td>错误分派——路由错了后面再强也难救</td></tr><tr><td>Parallel（并行）</td><td>撒</td><td>错误聚合——merge 不做好，只是把噪声并行化</td></tr><tr><td>Orchestrate（编排）</td><td>协</td><td>错误分解——该选链式的拆成并行，该共享状态的拆成独立</td></tr><tr><td>Loop（循环）</td><td>转</td><td>错误复合——越改越忙，越忙越偏</td></tr><tr><td>Hierarchy（层级）</td><td>分</td><td>错误放大或隔离——隔离没做好，父级泄漏给子级，权限继承太宽</td></tr></tbody></table><h3 id="关键洞见" tabindex="-1">关键洞见 <a class="header-anchor" href="#关键洞见" aria-label="Permalink to &quot;关键洞见&quot;">​</a></h3><blockquote><p>横轴不是流程图轴，而是<strong>错误的传播路径轴</strong>。选择了拓扑，就是选择了错误如何在系统里移动。</p></blockquote><h3 id="各拓扑核心要点" tabindex="-1">各拓扑核心要点 <a class="header-anchor" href="#各拓扑核心要点" aria-label="Permalink to &quot;各拓扑核心要点&quot;">​</a></h3><ul><li><strong>Chain</strong>：优点可预测，缺点错误会顺流而下。链越长中间格式越重要。</li><li><strong>Route</strong>：核心是分类器质量。路由的工程价值在于降低平均成本和风险，不在于提高上限。</li><li><strong>Parallel</strong>：关键在 merge，不在 fan-out。数学题可以多数投票，创意题不能。</li><li><strong>Orchestrate</strong>：失败模式是拆错边界。该委派给专家的留在中心硬做。</li><li><strong>Loop</strong>：核心是停止条件、评估信号、每轮改动幅度。没有这些会越转越偏。</li><li><strong>Hierarchy</strong>：失败模式是隔离没做好——父级上下文泄漏给所有子级，权限继承太宽。</li></ul><hr><h2 id="双轴合一的判断标准" tabindex="-1">双轴合一的判断标准 <a class="header-anchor" href="#双轴合一的判断标准" aria-label="Permalink to &quot;双轴合一的判断标准&quot;">​</a></h2><p><img src="'+s+`" alt="七脉×六式双轴矩阵全景"></p><blockquote><p><strong>纵七脉定资源得失，横六式断错误路径。</strong></p></blockquote><p>一个 Agent 架构缺哪一脉，就会在哪一类资源上失控。 选择了拓扑，就是选择了错误如何传播。</p><hr><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to &quot;思考题&quot;">​</a></h2><ol><li>你正在做或见过的 Agent 系统，最容易失控的是哪一类资源？</li><li>找一个熟悉的 Agent 工作流，判断它主要采用哪种执行拓扑，这种拓扑最容易让错误沿什么路径传播？</li><li>为什么&quot;用了几个 Agent&quot;&quot;接了几个工具&quot;还不足以说明系统设计得好？用七脉和六式重新描述这个系统。</li></ol><hr><h2 id="关键对话总结" tabindex="-1">关键对话总结 <a class="header-anchor" href="#关键对话总结" aria-label="Permalink to &quot;关键对话总结&quot;">​</a></h2><h3 id="_1-为什么需要双轴框架" tabindex="-1">1. 为什么需要双轴框架 <a class="header-anchor" href="#_1-为什么需要双轴框架" aria-label="Permalink to &quot;1. 为什么需要双轴框架&quot;">​</a></h3><p>市面上已有的 Agent 分类（Weng 数模块、Anthropic 数 Workflow、Andrew Ng 数模式、Chip Huyen 数工程角色）都是从不同方向给同一个立方体画三视图——每个视图都是真的，但没有一张能还原整体结构。双轴框架就是那个<strong>立方体本身</strong>。</p><h3 id="_2-纵轴七脉-七种资源预算" tabindex="-1">2. 纵轴七脉：七种资源预算 <a class="header-anchor" href="#_2-纵轴七脉-七种资源预算" aria-label="Permalink to &quot;2. 纵轴七脉：七种资源预算&quot;">​</a></h3><p>七脉回答的不是&quot;Agent 能做多少事&quot;，而是 <strong>&quot;Agent 在花什么资源&quot;</strong>：</p><table tabindex="0"><thead><tr><th>脉</th><th>你管的是什么预算</th><th>缺了会怎样</th></tr></thead><tbody><tr><td>感知</td><td>注意力预算——什么信息值得看</td><td>token 失控</td></tr><tr><td>记忆</td><td>连续性预算——跨时间保留什么</td><td>连续性失控</td></tr><tr><td>推理</td><td>不确定性预算——怎么从前提走到结论</td><td>判断失控</td></tr><tr><td>行动</td><td>可逆性预算——做了能不能撤回</td><td>世界状态失控</td></tr><tr><td>反思</td><td>校正预算——刚才对不对，下一步怎么改</td><td>错误失控</td></tr><tr><td>协作</td><td>分工预算——任务怎么拆给多个 Agent</td><td>规模失控</td></tr><tr><td>治理</td><td>信任预算——怎么限制、记录、审计</td><td>信任失控</td></tr></tbody></table><p>七脉又分三层：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>内圈（核心认知）：感知 → 记忆 → 推理 → 行动   让 Agent 能用</span></span>
<span class="line"><span>中圈（元认知）：   反思                          让 Agent 可靠</span></span>
<span class="line"><span>外圈（系统智能）：  协作 + 治理                  让 Agent 能上线</span></span></code></pre></div><h3 id="_3-实战案例-你的生成应用-agent-失控在哪一脉" tabindex="-1">3. 实战案例：你的生成应用 Agent 失控在哪一脉 <a class="header-anchor" href="#_3-实战案例-你的生成应用-agent-失控在哪一脉" aria-label="Permalink to &quot;3. 实战案例：你的生成应用 Agent 失控在哪一脉&quot;">​</a></h3><p>你做过的生成完整应用的 Agent，最容易失控的是<strong>记忆脉</strong>——Agent 要生成多个文件、多次决策、多轮修改，上一轮决定了什么下一轮还记不记得，就是记忆脉管的事。</p><p>你的解决方案（&quot;先生成一个个任务，每次只做一个&quot;）本质上是<strong>降低对记忆的依赖</strong>——每一步要记的东西变少了，上下文就不容易炸。</p><h3 id="_4-横轴六式-错误的传播路径" tabindex="-1">4. 横轴六式：错误的传播路径 <a class="header-anchor" href="#_4-横轴六式-错误的传播路径" aria-label="Permalink to &quot;4. 横轴六式：错误的传播路径&quot;">​</a></h3><p>横轴回答的不是&quot;流程怎么走&quot;，而是**&quot;错误怎么传播&quot;**。选了拓扑，就是选了错误在系统里怎么移动。</p><table tabindex="0"><thead><tr><th>拓扑</th><th>动词</th><th>错误传播方式</th></tr></thead><tbody><tr><td>Chain（链式）</td><td>传</td><td>错误级联——一步走偏，下游不会纠错反而包装错误</td></tr><tr><td>Route（路由）</td><td>选</td><td>错误分派——路由错了后面再强也难救</td></tr><tr><td>Parallel（并行）</td><td>撒</td><td>错误聚合——merge 没做好，噪声只会放大</td></tr><tr><td>Orchestrate（编排）</td><td>协</td><td>错误分解——拆错边界，中心做不了的事硬做</td></tr><tr><td>Loop（循环）</td><td>转</td><td>错误复合——越改越偏</td></tr><tr><td>Hierarchy（层级）</td><td>分</td><td>错误放大或隔离——父级泄漏给子级，权限太宽</td></tr></tbody></table><h3 id="_5-实战案例-chain-的致命弱点" tabindex="-1">5. 实战案例：Chain 的致命弱点 <a class="header-anchor" href="#_5-实战案例-chain-的致命弱点" aria-label="Permalink to &quot;5. 实战案例：Chain 的致命弱点&quot;">​</a></h3><p>你的生成应用天然是<strong>Chain</strong>——生成文件 A → 生成文件 B → 生成文件 C，每个步骤依赖前面的输出。Chain 的致命弱点就是<strong>错误级联</strong>：中间任何一个模块结构错了，后面依赖它的文件只会越偏越离谱。</p><p>你的改进方案（先生成任务列表，再逐个完成）本质上是在<strong>把 Chain 拆成 Orchestrate</strong>：先规划再执行，每步有独立验证，错误被隔离在单个任务内。</p><h3 id="_6-一句话带走" tabindex="-1">6. 一句话带走 <a class="header-anchor" href="#_6-一句话带走" aria-label="Permalink to &quot;6. 一句话带走&quot;">​</a></h3><blockquote><p><strong>纵七脉定资源得失，横六式断错误路径。</strong> 双轴框架是一张坐标图，后面所有 Agent 模式（感知、记忆、推理、行动……）都可以在这张图上定位——它属于哪一脉（花什么资源），用哪种拓扑（错误怎么传）。</p></blockquote>`,54)])])}const _=a(l,[["render",i]]);export{q as __pageData,_ as default};
